import puppeteer from 'puppeteer';
import fs from 'fs';
import path from 'path';

/**
 * Generates a professional PDF for Template 3 (Features Explained).
 * @param {Object} quotationData - The JSON generated by AI for Template 3.
 * @returns {Promise<Buffer>} The PDF buffer.
 */
export const generateQuotationPDFTemplate3 = async (quotationData) => {
    const browser = await puppeteer.launch({
        headless: "new",
        args: ["--no-sandbox", "--disable-setuid-sandbox"],
    });

    const page = await browser.newPage();

    let logoBase64 = "";
    try {
        const logoPath = path.resolve('assets/logo.png');
        if (fs.existsSync(logoPath)) {
            logoBase64 = `data:image/png;base64,${fs.readFileSync(logoPath).toString('base64')}`;
        }
    } catch (err) {
        console.error("Error reading logo:", err);
    }

    // Corporate Palette
    const t = {
        primary: '#1E3A8A',     // Deep Blue
        secondary: '#334155',   // Slate Gray
        accent: '#06B6D4',      // Teal / Cyan
        bg: '#F8FAFC',          // Light gray sections background
        text: '#1E293B',        // Dark slate for text
        border: '#E2E8F0',
        white: '#FFFFFF'
    };

    const logoUrl = "https://res.cloudinary.com/dt4vwprm3/image/upload/v1764744525/WhatsApp_Image_2025-12-03_at_12.13.54_PM_rhgci7.jpg";

    const headerBlock = (title) => `
        <div style="display:flex; justify-content:space-between; align-items:flex-end; border-bottom: 2px solid ${t.primary}; padding-bottom: 15px; margin-bottom: 30px;">
            <div>
                <h2 style="font-family: 'Montserrat', sans-serif; font-weight: 700; font-size: 20px; color: ${t.primary}; margin: 0; text-transform: uppercase; letter-spacing: 1px;">
                    ${title}
                </h2>
            </div>
            <div style="text-align:right;">
                <img src="${logoUrl}" style="height:35px; object-fit:contain;" />
            </div>
        </div>
    `;

    const htmlContent = `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&family=Montserrat:wght@600;700;800&display=swap" rel="stylesheet">
    <style>
        @page {
            size: A4;
            margin: 20mm 20mm 25mm 20mm;
        }
        @page :first {
            margin: 0;
        }
        * { box-sizing: border-box; -webkit-print-color-adjust: exact; }
        body {
            font-family: 'Inter', sans-serif;
            margin: 0; padding: 0;
            color: ${t.text};
            background: ${t.white};
            line-height: 1.6;
        }
        .page-break {
            page-break-before: always;
            padding-top: 10px;
        }
        h1, h2, h3, h4 { font-family: 'Montserrat', sans-serif; color: ${t.primary}; margin-top: 0; }
        
        /* Watermark - Fixed to repeat on every page */
        .watermark {
            position: fixed;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%) rotate(-45deg);
            font-size: 65px;
            color: rgba(30, 58, 138, 0.04);
            font-family: 'Montserrat', sans-serif;
            font-weight: 800;
            z-index: 1;
            white-space: nowrap;
            pointer-events: none;
        }

        /* Global Footer - placed naturally in the tfoot to repeat at bottom of each page */
        .global-footer {
            border-top: 1px solid ${t.border};
            padding-top: 5px;
            margin-top: 5mm; /* push down slightly from content */
            display: flex;
            justify-content: space-between;
            align-items: flex-end;
            font-size: 9px;
            color: ${t.secondary};
            font-weight: 500;
        }

        /* The table header and footer spaces ensure content doesn't overlap the fixed elements */
        .layout-table { width: 100%; border: none; border-collapse: collapse; }
        .layout-table td { padding: 0; border: none; }
        .spacer-header { height: 1px; }

        /* Cover Page */
        .cover-container {
            display: flex;
            width: 210mm;
            height: 297mm;
            background: ${t.white};
            position: relative;
            z-index: 50; /* Covers the fixed watermark and everything else on first page */
            margin-top: -1px; /* offset the spacer-header on first page */
        }
        .cover-left {
            flex: 1.2;
            padding: 40px 30px 40px 20mm;
            display: flex;
            flex-direction: column;
            justify-content: center;
        }
        .cover-right {
            flex: 0.8;
            background: linear-gradient(135deg, ${t.primary} 0%, ${t.accent} 100%);
            border-top-left-radius: 60px;
            border-bottom-left-radius: 60px;
            position: relative;
            overflow: hidden;
        }
        .cover-right::after {
            content: "";
            position: absolute;
            top: -10%; left: -20%;
            width: 150%; height: 150%;
            background: repeating-linear-gradient(45deg, rgba(255,255,255,0.05) 0px, rgba(255,255,255,0.05) 20px, transparent 20px, transparent 40px);
        }

        /* Generic Table Styling */
        table {
            width: 100%; border-collapse: collapse; margin-bottom: 25px;
            font-size: 13px;
        }
        th, td {
            padding: 12px 15px; text-align: left; border-bottom: 1px solid ${t.border};
            page-break-inside: avoid;
        }
        th {
            background-color: ${t.bg}; color: ${t.primary}; font-weight: 600; font-family: 'Montserrat', sans-serif;
        }
        tr:nth-child(even) { background-color: #F8FAFC55; }
        tr { page-break-inside: avoid; } /* prevent rows from splitting */

        /* Tech Stack Badges */
        .badge {
            display: inline-block; padding: 6px 12px; margin: 0 6px 8px 0;
            background: ${t.bg}; border: 1px solid ${t.border}; border-radius: 4px;
            font-size: 12px; font-weight: 500; color: ${t.secondary};
        }

        /* Module boxes */
        .module-box {
            border-left: 3px solid ${t.accent};
            padding: 15px 20px;
            margin-bottom: 20px;
            background: ${t.white};
            border-top: 1px solid ${t.border};
            border-right: 1px solid ${t.border};
            border-bottom: 1px solid ${t.border};
            box-shadow: 0 4px 6px -1px rgba(0,0,0,0.02);
            page-break-inside: avoid;
        }

        .highlight-box {
            background: rgba(30, 58, 138, 0.04); /* highly transparent primary */
            border-left: 4px solid ${t.primary};
            padding: 15px 20px;
            border-radius: 0 6px 6px 0;
            margin-bottom: 20px;
            page-break-inside: avoid;
        }
        
        ul { padding-left: 20px; margin-top: 5px; }
        li { margin-bottom: 6px; font-size: 13px; page-break-inside: avoid; }
    </style>
</head>
<body>
<div class="watermark">Argosmob Tech and AI Pvt LTD</div>

<!-- 1. Cover Page -->
<div>
    <div class="cover-container">
        <div class="cover-left">
            <img src="${logoUrl}" style="height:60px; object-fit:contain; margin-bottom: 80px;" />
            <div style="text-transform:uppercase; letter-spacing:3px; color:${t.secondary}; font-size:12px; margin-bottom:15px; font-weight:600;">Project Proposal</div>
            <h1 style="font-size:42px; line-height:1.2; margin-bottom:20px;">${quotationData.projectName || 'Software Solution Proposal'}</h1>
            <div style="width: 60px; height: 5px; background: ${t.accent}; margin-bottom: 40px;"></div>
            
            <table style="width:100%; border:none; margin-bottom:0;">
                <tr style="background:transparent;">
                    <td style="padding:5px 0; border:none; color:${t.secondary}; font-size:12px; font-weight:600; width:50%;">PREPARED FOR</td>
                    <td style="padding:5px 0; border:none; color:${t.secondary}; font-size:12px; font-weight:600; width:50%;">PREPARED BY</td>
                </tr>
                <tr style="background:transparent;">
                    <td style="padding:0 0 20px 0; border:none; font-size:16px; font-weight:700; color:${t.primary};">${quotationData.clientName || 'Valued Client'}</td>
                    <td style="padding:0 0 20px 0; border:none; font-size:15px; font-weight:600; color:${t.text};">Argosmob Tech & AI Pvt. Ltd.</td>
                </tr>
                <tr style="background:transparent;">
                    <td colspan="2" style="padding:5px 0; border:none; color:${t.secondary}; font-size:12px; font-weight:600;">DATE</td>
                </tr>
                <tr style="background:transparent;">
                    <td colspan="2" style="padding:0 0 20px 0; border:none; font-size:14px; font-weight:500;">${new Date().toLocaleDateString('en-IN', { day: '2-digit', month: 'long', year: 'numeric' })}</td>
                </tr>
            </table>
        </div>
        <div class="cover-right">
            <!-- decorative right side block -->
        </div>
    </div>
</div>

<table class="layout-table" style="page-break-before: always;">
  <thead><tr><td><div class="spacer-header"></div></td></tr></thead>
  <tfoot>
    <tr>
      <td>
        <div class="global-footer">
            <div style="display:flex; flex-direction:column; gap:4px;">
                <span>Email: hello@argosmob.onmicrosoft.com</span>
                <span>Address: 618, Hope Tower, Galaxy Blue Saffaire, Gr. Noida West, 201009</span>
            </div>
            <div style="text-align:right; display:flex; flex-direction:column; justify-content:flex-end;">
                <span>Corporate Proposal</span>
            </div>
        </div>
      </td>
    </tr>
  </tfoot>
  <tbody><tr><td>

    <!-- 2. Introduction & 5. Delivery Scope -->
    <div>
        ${headerBlock('1. Executive Overview')}
        
        <div class="highlight-box">
            <h3 style="font-size:16px; margin-bottom:10px;">Project Introduction</h3>
            <p style="font-size:14px; margin:0;">${quotationData.introduction || ''}</p>
        </div>

        <h3 style="font-size:18px; margin-top:40px; margin-bottom:15px; border-bottom:1px solid ${t.border}; padding-bottom:10px;">2. Delivery Scope</h3>
        <p style="font-size:13px; color:${t.secondary};">The following core components are included in the delivery of this engagement:</p>
        <div style="display:grid; grid-template-columns: 1fr 1fr; gap:15px; margin-top:20px;">
            ${(quotationData.deliveryScope || []).map(item => `
                <div style="display:flex; align-items:center; gap:10px; page-break-inside: avoid;">
                    <div style="width:8px; height:8px; background:${t.accent}; border-radius:50%;"></div>
                    <span style="font-size:14px; font-weight:500;">${item}</span>
                </div>
            `).join('')}
        </div>
    </div>

    <!-- 3. Key Modules -->
    <div class="page-break">
        ${headerBlock('3. Functional Modules')}
        <p style="font-size:13px; margin-bottom:25px;">The solution architecture is broken down into the following key functional modules.</p>
        
        ${(quotationData.keyModules || quotationData.features || []).map((mod, idx) => `
            <div class="module-box">
                <h4 style="font-size:15px; margin-bottom:8px; display:flex; align-items:center; gap:10px;">
                    <span style="color:${t.accent}; font-weight:800;">${String(idx + 1).padStart(2, '0')}.</span> ${mod.title || mod.module}
                </h4>
                ${mod.description ? `<p style="font-size:13px; margin-bottom:16px; color:${t.secondary};">${mod.description}</p>` : ''}
                <ul style="margin:0; padding-left:15px; list-style:none;">
                    ${(mod.features || mod.items || []).map(f => {
        let featureName = "";
        let descriptionLines = [f];

        if (typeof f === 'string') {
            // Extract "Feature Name:" if it exists
            if (f.includes(':')) {
                const parts = f.split(':');
                featureName = parts.shift().trim();
                const rest = parts.join(':').trim();
                descriptionLines = rest.split('\\n').map(line => line.trim()).filter(Boolean);
            } else {
                descriptionLines = f.split('\\n').map(line => line.trim()).filter(Boolean);
            }
        }

        return '<li style="margin-bottom:12px; page-break-inside:avoid;">' +
            '<div style="display:flex; align-items:flex-start; gap:8px;">' +
            '<div style="color:' + t.primary + '; font-weight:bold; margin-top:2px;">•</div>' +
            '<div>' +
            (featureName ? '<div style="font-weight:700; color:' + t.primary + '; font-size:13px; margin-bottom:2px;">' + featureName + '</div>' : '') +
            descriptionLines.map(line => '<div style="font-size:12px; color:' + t.secondary + '; line-height:1.5;">' + line + '</div>').join('') +
            '</div>' +
            '</div>' +
            '</li>';
    }).join('')}
                </ul>
            </div>
        `).join('')}
    </div>

    <!-- 4. Tech Stack & 7. Proposed Team -->
    <div class="page-break">
        ${headerBlock('4. Technology & Resourcing')}
        
        <h3 style="font-size:18px; margin-bottom:15px;">Technology Stack</h3>
        <table style="margin-bottom: 40px;">
            <tr>
                <th style="width:30%;">Domain</th>
                <th>Proposed Technologies</th>
            </tr>
            ${Array.isArray(quotationData.techStack)
            ? `<tr><td>Core Tech</td><td>${(quotationData.techStack || []).map(t => `<span class="badge">${t}</span>`).join('')}</td></tr>`
            : Object.entries(quotationData.techStack || {}).map(([key, tools]) => `
                <tr>
                    <td style="text-transform:capitalize; font-weight:600; color:${t.secondary};">${key}</td>
                    <td>${(tools || []).map(tool => `<span class="badge">${tool}</span>`).join('')}</td>
                </tr>
            `).join('')}
        </table>

        <h3 style="font-size:18px; margin-bottom:15px; margin-top: 40px;">Proposed Team Structure</h3>
        <table>
            <tr>
                <th style="width:10%;">S.No.</th>
                <th style="width:60%;">Role</th>
                <th style="width:30%;">Allocation (Count)</th>
            </tr>
            ${(quotationData.proposedTeam || []).map((teamMember, idx) => `
                <tr>
                    <td>${idx + 1}</td>
                    <td style="font-weight:500;">${teamMember.role}</td>
                    <td>${teamMember.count} Resource(s)</td>
                </tr>
            `).join('')}
        </table>
    </div>

    <!-- 6. Cost & Timeline -->
    <div class="page-break" style="background:${t.bg}; padding: 25px; border-radius: 8px;">
        ${headerBlock('5. Commercials & Timeline')}

        <div style="background:${t.white}; padding:30px; border-radius:8px; border:1px solid ${t.border}; margin-bottom:30px; box-shadow: 0 4px 6px -1px rgba(0,0,0,0.05);">
            <div style="font-size:12px; color:${t.secondary}; text-transform:uppercase; letter-spacing:1px; margin-bottom:5px;">Total Investment</div>
            <h2 style="font-size:32px; color:${t.primary}; margin-bottom:5px;">${quotationData.costEstimation?.totalCost || quotationData.commercialEstimate || 'TBD'}</h2>
            <div style="font-size:11px; color:${t.secondary};">*Exclusive of prevailing taxes and 3rd-party subscriptions.</div>
        </div>

        <h3 style="font-size:16px; margin-bottom:15px; margin-top:20px;">Payment Milestones</h3>
        <table>
            <tr>
                <th style="width:10%;">S.No.</th>
                <th style="width:40%;">Milestone</th>
                <th style="width:20%;">Percentage</th>
                <th style="width:30%;">Amount</th>
            </tr>
            ${(quotationData.costEstimation?.paymentPlan || quotationData.paymentPlan || []).map((p, idx) => `
                <tr>
                    <td>${idx + 1}</td>
                    <td>${typeof p === 'object' ? p.milestone : p}</td>
                    <td style="font-weight:600;">${typeof p === 'object' ? p.percentage : '-'}</td>
                    <td>${typeof p === 'object' ? p.amount : '-'}</td>
                </tr>
            `).join('')}
        </table>

        <h3 style="font-size:16px; margin-top:40px; margin-bottom:15px;">Implementation Timeline</h3>
        <table>
            <tr>
                <th style="width:10%;">S.No.</th>
                <th style="width:30%;">Phase</th>
                <th style="width:20%;">Duration</th>
                <th style="width:40%;">Key Deliverables</th>
            </tr>
            ${(quotationData.timeline || []).map((tl, idx) => `
                <tr>
                    <td>${idx + 1}</td>
                    <td style="font-weight:600;">${tl.phase}</td>
                    <td>${tl.duration}</td>
                    <td style="font-size:12px;">${tl.deliverables || (tl.tasks || []).join(', ')}</td>
                </tr>
            `).join('')}
        </table>
    </div>

    <!-- 8-13. Service & Legal -->
    <div class="page-break">
        ${headerBlock('6. Post-Deployment & Governance')}

        <div style="margin-bottom: 30px;">
            <h4 style="font-size:15px; margin-bottom:5px; color:${t.primary};">Service Level Agreement (SLA)</h4>
            <div style="font-size:13px; margin-bottom:15px;"><strong>Coverage:</strong> ${quotationData.sla?.maintenanceCoverage || 'Standard Support'}</div>
            <table>
                <tr>
                    <th style="width:10%;">S.No.</th>
                    <th>Metric</th>
                    <th>Target</th>
                </tr>
                <tr>
                    <td>1</td>
                    <td>Response Times</td>
                    <td><ul style="margin:0; padding-left:15px;">${(quotationData.sla?.responseTimes || []).map(r => `<li>${r}</li>`).join('')}</ul></td>
                </tr>
                <tr>
                    <td>2</td>
                    <td>Resolution Times</td>
                    <td><ul style="margin:0; padding-left:15px;">${(quotationData.sla?.resolutionTimes || []).map(r => `<li>${r}</li>`).join('')}</ul></td>
                </tr>
            </table>
        </div>

        <div class="highlight-box" style="padding:15px; margin-bottom:20px; border-left-color:${t.secondary}; background:${t.bg}; border-radius:4px;">
            <h4 style="font-size:14px; margin-bottom:5px;">Annual Maintenance Contract (AMC)</h4>
            <p style="font-size:13px; margin:0;">${quotationData.amc || 'Details to be appended.'}</p>
        </div>

        <div style="margin-bottom: 25px;">
            <h4 style="font-size:14px; margin-bottom:5px;">Change Request Management</h4>
            <p style="font-size:13px; color:${t.secondary}; margin:0;">${quotationData.changeRequest || 'Any additional features not outlined in the scope will be considered a Change Request (CR) and billed separately.'}</p>
        </div>

        <div style="margin-bottom: 25px;">
            <h4 style="font-size:14px; margin-bottom:5px;">Acceptance Criteria</h4>
            <ul style="margin:0; color:${t.secondary};">
                ${(quotationData.acceptanceCriteria || []).map(c => `<li>${c}</li>`).join('')}
            </ul>
        </div>

        <div style="margin-bottom: 25px;">
            <h4 style="font-size:14px; margin-bottom:5px;">Warranty</h4>
            <p style="font-size:13px; color:${t.secondary}; margin:0;">${quotationData.warranty || '60 Days defect liability period post UAT sign-off.'}</p>
        </div>
    </div>

    <!-- 14. Sign Off -->
    <div class="page-break">
        ${headerBlock('7. Sign Off & Acceptance')}

        <h3 style="font-size:18px; margin-bottom:15px;">Legal & Compliance</h3>
        <p style="font-size:13px; color:${t.secondary}; line-height: 1.8; margin-bottom:50px;">
            ${quotationData.legal || 'This document is strictly confidential and intended solely for the use of the individual or entity to whom it is addressed. Both parties agree to a mutual Non-Disclosure Agreement (NDA) ensuring the protection of intellectual property, technical specifications, and commercial data shared during this engagement.'}
        </p>

        <div style="background:${t.bg}; padding:35px; border-top: 3px solid ${t.primary}; border-radius:8px;">
            <h3 style="font-size:16px; margin-bottom:45px; text-transform:uppercase;">Authorization & Acceptance</h3>
            
            <div style="display:grid; grid-template-columns: 1fr 1fr; gap:60px;">
                <div>
                    <div style="border-bottom:1px solid ${t.secondary}; height:40px; margin-bottom:12px;"></div>
                    <div style="font-size:13px; font-weight:700; color:${t.primary};">Authorized Signatory</div>
                    <div style="font-size:11px; color:${t.secondary};">ArgosMob Tech &amp; AI Pvt. Ltd.</div>
                    <div style="font-size:11px; color:${t.secondary}; margin-top:5px;">Date: ________________</div>
                </div>
                <div>
                    <div style="border-bottom:1px solid ${t.secondary}; height:40px; margin-bottom:12px;"></div>
                    <div style="font-size:13px; font-weight:700; color:${t.primary};">Authorized Signatory</div>
                    <div style="font-size:11px; color:${t.secondary};">${quotationData.clientName || 'Client'}</div>
                    <div style="font-size:11px; color:${t.secondary}; margin-top:5px;">Date: ________________</div>
                </div>
            </div>
        </div>
    </div>

  </td></tr></tbody>
</table>

</body>
</html>`;

    await page.setContent(htmlContent, { waitUntil: 'networkidle0' });

    const pdfBuffer = await page.pdf({
        format: 'A4',
        preferCSSPageSize: true, // IMPORTANT: Respects our @page margins
        printBackground: true,
        displayHeaderFooter: false, // Using fixed CSS elements for footer
    });

    await browser.close();
    return pdfBuffer;
};
